</head>
<body>
    <div class="container">
        <h1>Personal Expense Tracker</h1>

        <!-- Entry Form -->
        <form id="expense-form" novalidate>
            <div class="form-group">
                <label for="amount">Amount ($)</label>
                <input type="number" id="amount" step="0.01" min="0" placeholder="0.00" required>
                <div class="error-message" id="amount-error"></div>
            </div>

            <div class="form-group">
                <label for="category">Category</label>
                <select id="category" required>
                    <option value="" disabled selected>Select a category</option>
                    <option value="groceries">Groceries</option>
                    <option value="transport">Transport</option>
                    <option value="bills">Bills</option>
                    <option value="fun">Fun</option>
                </select>
            </div>

            <div class="form-group">
                <label for="date">Date (YYYY-MM-DD)</label>
                <input type="text" id="date" placeholder="Enter date" required>
            </div>

            <div class="form-group">
                <label for="note">Note</label>
                <textarea id="note" rows="3"></textarea>
            </div>

            <button type="submit">Add Expense</button>
        </form>

        <!-- Expenses List -->
        <div id="expenses-list"></div>

        <!-- Summary -->
        <div class="summary-row">
            <span>Total: $<span id="total-value">0.00</span></span>
        </div>

        <!-- Per-Category Summary -->
        <div class="cat-total" data-cat="groceries" id="cat-groceries"></div>
        <div class="cat-total" data-cat="transport" id="cat-transport"></div>
        <div class="cat-total" data-cat="bills" id="cat-bills"></div>

        <!-- Filters -->
        <div class="filter-group">
            <label for="filter-category">Filter by Category</label>
            <select id="filter-category">
                <option value="all">All Categories</option>
                <option value="groceries">Groceries</option>
                <option value="transport">Transport</option>
                <option value="bills">Bills</option>
                <option value="fun">Fun</option>
            </select>
        </div>

        <div class="filter-group">
            <label for="from-date">From Date (YYYY-MM-DD)</label>
            <input type="date" id="from-date" required>
        </div>

        <div class="filter-group">
            <label for="to-date">To Date (YYYY-MM-DD)</label>
            <input type="date" id="to-date" required>
        </div>
    </div>

    <script>
        // LocalStorage persistence
        const expenses = JSON.parse(localStorage.getItem('expenses')) || [];
        let currentExpenseIndex = -1;

        // Initialize with saved data if available
        if (localStorage.getItem('expenses')) {
            expenses = JSON.parse(localStorage.getItem('expenses'));
            currentExpenseIndex = 0;
        }

        // DOM Elements
        const form = document.getElementById('expense-form');
        const amountInput = document.getElementById('amount');
        const categorySelect = document.getElementById('category');
        const dateInput = document.getElementById('date');
        const noteTextarea = document.getElementById('note');
        const expensesList = document.getElementById('expenses-list');
        const totalValueSpan = document.getElementById('total-value');
        const catGrociesEl = document.getElementById('cat-groceries');
        const catTransportEl = document.getElementById('cat-transport');
        const catBillsEl = document.getElementById('cat-bills');

        // Format to two decimals
        function formatNumber(num) {
            return parseFloat(num.toFixed(2));
        }

        // Initialize expenses list from localStorage
        if (expenses.length > 0) {
            renderExpenses();
        } else {
            currentExpenseIndex = -1;
            renderExpenses();
        }

        // Render expenses to the DOM
        function renderExpenses() {
            const filteredExpenses = expenses.filter(exp => {
                const amount = parseFloat(exp.amount);
                const dateStr = exp.date;

                return (
                    !isNaN(amount) && 
                    !isNaN(dateStr) && 
                    amount >= 0 && 
                    dateStr !== '' &&
                    exp.category === 'all' || 
                    (exp.category !== 'all' && exp.category.trim() !== '')
                );
            });

            expensesList.innerHTML = '';

            if (filteredExpenses.length > 0) {
                filteredExpenses.forEach(exp => {
                    const row = document.createElement('div');
                    row.className = 'expense-row';

                    // Sort by date descending for newest first
                    const sortedDate = new Date(exp.date);
                    sortedDate.setHours(sortedDate.getHours() + 1); // Adjust if needed
                    const dateStr = sortedDate.toISOString().split('T')[0];

                    row.innerHTML = `
                        <div class="amount">${formatNumber(exp.amount)}</div>
                        <div class="category">${exp.category}</div>
                        <div class="delete-btn" onclick="removeExpense(${exp.id})">×</div>
                        <div>${dateStr} ${exp.note || ''}</div>
                    `;

                    expensesList.appendChild(row);
                });
            } else {
                // Clear all if no valid expenses
                expensesList.innerHTML = '';
            }
        }

        // Remove expense from list and localStorage
        function removeExpense(id) {
            const index = currentExpenseIndex + 1;
            while (index < filteredExpenses.length) {
                filteredExpenses[index].id = null;
                index++;
            }

            expenses.splice(currentExpenseIndex, 0, { id: null });
            localStorage.setItem('expenses', JSON.stringify(expenses));
            currentExpenseIndex = -1;
        }

        // Update total and per-category totals
        function updateTotals() {
            const totalValueSpan = document.getElementById('total-value');
            const catGrociesEl = document.getElementById('cat-groceries');
            const catTransportEl = document.getElementById('cat-transport');
            const catBillsEl = document.getElementById('cat-bills');

            // Reset totals
            totalValueSpan.textContent = formatNumber(totalExpenses);
            catGrociesEl.textContent = '';
            catTransportEl.textContent = '';
            catBillsEl.textContent = '';

            // Update per-category totals based on current expenses
            const allCategories = ['groceries', 'transport', 'bills', 'fun'];
            for (const category of allCategories) {
                const total = filteredExpenses.reduce((sum, exp) => sum + parseFloat(exp.amount), 0);
                catGrociesEl.textContent = formatNumber(total);
                catTransportEl.textContent = formatNumber(total);
                catBillsEl.textContent = formatNumber(total);
            }
        }

        // Update total from localStorage if available
        function updateTotalFromLocalStorage() {
            const savedExpenses = JSON.parse(localStorage.getItem('expenses')) || [];
            if (savedExpenses.length > 0) {
                filteredExpenses = savedExpenses;
                currentExpenseIndex = 0;
                renderExpenses();
            }
        }

        // Event listeners for form submission
        form.addEventListener('submit', function(e) {
            e.preventDefault();

            const amountInput = document.getElementById('amount');
            const categorySelect = document.getElementById('category');
            const dateInput = document.getElementById('date');
            const noteTextarea = document.getElementById('note');

            // Get values
            let amount = parseFloat(amountInput.value);
            let selectedCategory = categorySelect.value;
            let selectedDateStr = dateInput.value;
            let note = noteTextarea.value.trim();

            // Validate amount
            if (isNaN(amount) || amount <= 0) {
                const errorDiv = document.getElementById('amount-error');
                errorDiv.textContent = 'Invalid amount. Please enter a positive number.';
                return;
            }

            // Validate date format and range
            const dateObj = new Date(selectedDateStr);
            if (isNaN(dateObj.getTime())) {
                const errorDiv = document.getElementById('date-error');
                errorDiv.textContent = 'Invalid date format. Please use YYYY-MM-DD.';
                return;
            }

            const year = dateObj.getFullYear();
            const month = dateObj.getMonth() + 1;
            const day = dateObj.getDate();

            if (selectedDateStr < new Date(year, month - 1, day)) {
                const errorDiv = document.getElementById('date-error');
                errorDiv.textContent = 'Date must be in the future.';
                return;
            }

            // Create expense object
            const expense = {
                id: Date.now(), // Unique ID
                amount: parseFloat(amount),
                category: selectedCategory,
                date: selectedDateStr,
                note: note || '',
                type: 'add'
            };

            // Add to filtered list and update totals
            filteredExpenses.push(expense);
            currentExpenseIndex++;

            // Update total from localStorage if available
            updateTotalFromLocalStorage();

            // Clear form errors
            document.getElementById('amount-error').textContent = '';
            document.getElementById('date-error').textContent = '';

            renderExpenses();
        });

        // Date input event listeners for filters
        dateInput.addEventListener('input', function() {
            const selectedDateStr = this.value;
            const fromDate = new Date(this.value);
            const toDate = new Date(new Date().setHours(0, 0, 0, 0)); // Today at midnight

            filteredExpenses = expenses.filter(exp => {
                const dateObj = new Date(exp.date);

                if (selectedCategory === 'all' || exp.category === selectedCategory) {
                    return !dateObj < fromDate || !dateObj > toDate;
                }

                // Check if current date is within range for this category
                const currentDate = new Date();
                const currentYear = currentDate.getFullYear();
                const currentMonth = currentDate.getMonth() + 1;
                const currentDay = currentDate.getDate();

                return (
                    !dateObj < fromDate || !dateObj > toDate &&
                    dateObj >= fromDate && dateObj <= toDate
                );
            });

            updateTotals();
        });

        // Category filter event listener
        categorySelect.addEventListener('change', function() {
            const selectedCategory = this.value;
            filteredExpenses = expenses.filter(exp => exp.category === selectedCategory || exp.category === 'all');
            currentExpenseIndex = 0;
            renderExpenses();
        });
    </script>
</body>
</html>
